export type Jid = string;
export type Minion = string;

export enum Out {
  HIGHSTATE = "highstate",
}

export enum JobStatus {
  UNKNOWN,
  RUNNING,
  SUCCESS,
  FAILED,
}

export enum Retcode {
  UNKNOWN = -2, //
  RUNNING = -1, // State is running
  SUCCESS = 0, // State success
  FAILED = 1, // Rendering SLS Error
  ERROR = 2, // State failed
}

export interface JobResultObject {
  arg: string[];
  fun: string;
  jid: Jid;
  pid: number;
  ret: string;
  tgt: string;
  tgt_type: string;
  user: string;
}

export interface HighstatePChangeInfo {
  [key: string]: string;
}

export interface HighstatePChange {
  [key: string]: HighstatePChangeInfo;
}

export interface HighstateChange {
  [key: string]: string;
}

export interface HighstateResult {
  __id__: string;
  __run_num__: number;
  __sls__: string;
  __state_ran__?: boolean;
  changes: HighstateChange;
  comment: string;
  duration: number;
  name: string;
  pchanges: HighstatePChange;
  result: boolean | null;
  start_time: string;
}

export interface JobResultHighState {
  [key: string]: HighstateResult;
}

export type JobReturn =
  | boolean
  | string
  | string[]
  | JobResultObject
  | JobResultHighState;

export interface JobResultMinion {
  out?: Out;
  retcode: Retcode;
  return: JobReturn;
  success: boolean;
}

export interface JobResult {
  [key: string]: JobResultMinion;
}

export interface JobArgumentObject {
  [key: string]: string;
}

export type JobArgument = string | JobArgumentObject;

export enum JobDataStatus {
  BASIC,
  LOADING_DETAILS,
  FULL,
}

export interface Job {
  _stamp: string;
  jid: Jid;
  arg: JobArgument[];
  fun: string;
  tgt: string;
  tgtType: string;
  user: string;
  dataStatus: JobDataStatus;
  minions: Minion[];
  missing: Minion[];
  resultsCodes: Record<Minion, Retcode>;
  results: JobResult;
}

export interface Jobs {
  [key: string]: Job;
}

// State
export interface JobsState {
  jobs: Jobs;
}

export interface JobBaseResponse {
  Arguments: JobArgument[];
  Function: string;
  StartTime: string;
  Target: string;
  "Target-type": string;
  User: string;
}

// Response from runner.jobs.active
export type RunnerJobsActiveResponse = Record<Jid, RunnerJobsActiveMinion>;

export interface RunnerJobsActiveMinion extends JobBaseResponse {
  Returned: Minion[];
  Running: unknown[];
}

// Response from runner.jobs.list_jobs
export type RunnerJobsListJobsResponse = Record<Jid, JobBaseResponse>;

// Response From runner.jobs.list_job
export interface RunnerJobsListJobResponse extends JobBaseResponse {
  Minions: Minion[];
  Result: Record<Minion, JobResultMinion>;
  jid: Jid;
}
