import { api } from "@/api";
import { saltJobNewListener } from "@/store/events/listeners/salt-job-new";
import { saltJobRetListener } from "@/store/events/listeners/salt-job-ret";

type ListenerCallback<T = unknown> = (
  tag: string,
  data: T
) => void | Promise<void>;

interface Listener<T> {
  regexp: RegExp;
  cb: ListenerCallback<T>;
}

const listeners: Listener<never>[] = [];

function setupListener<T = unknown>(regexp: RegExp, cb: ListenerCallback<T>) {
  const listener: Listener<T> = {
    regexp,
    cb,
  };
  listeners.push(listener);
}

setupListener(/salt\/job\/\d+\/new/, saltJobNewListener);
setupListener(/salt\/job\/\d+\/ret\/\w+/, saltJobRetListener);

// setupListener(/\d+/, eventNewListener);

export function startConsumingEvents(): void {
  api.consumeEvents(async (tag: string, data: never) => {
    let consumed = false;
    listeners.forEach((listener: Listener<never>) => {
      if (tag.match(listener.regexp)) {
        listener.cb(tag, data);
        consumed = true;
      }
    });

    if (!consumed) {
      console.debug("consumeEvents callback: unknown event", tag, data);
    }
  });
}
