































import Vue from "vue";
import { mapGetters, mapMutations, mapState } from "vuex";

import { api } from "@/api";
import { getBaseInfo } from "@/store/utils";
import JobRunner from "@/components/JobRunner.vue";

export default Vue.extend({
  name: "App",
  components: {
    JobRunner,
  },
  data() {
    return {
      isBooted: false,
    };
  },
  created(): void {
    this.login();
  },
  computed: {
    ...mapState(["loggedin", "user"]),
    ...mapGetters("jobs", ["jobListRunning"]),
    userCapFirst(): boolean {
      return this.user.length
        ? this.user.charAt(0).toUpperCase() + this.user.slice(1)
        : this.user;
    },
  },
  methods: {
    ...mapMutations(["setLoggedin", "setLoggedout"]),
    async login(): Promise<void> {
      let isAuthenticated = false;
      try {
        isAuthenticated = await api.isAuthenticated();
      } catch (e) {
        console.error("isAuthenticated error", e);
        this.isBooted = true;
        return;
      }

      if (isAuthenticated) {
        this.setLoggedin();
        getBaseInfo();
        this.isBooted = true;
      } else {
        this.isBooted = true;
        await this.$router.push({ name: "login" });
      }
    },
    async logout(): Promise<void> {
      await api.logout();
      this.setLoggedout();
      await this.$router.push({ name: "login" });
    },
  },
});
