






































































import Vue from "vue";
import { api } from "@/api";
import { getBaseInfo } from "@/store/utils";
import { mapMutations } from "vuex";
import Backdrop from "@/components/Backdrop.vue";

interface Data {
  username: string;
  password: string;
  busy: boolean;
  error: null | string;
}

export default Vue.extend({
  name: "Login",
  components: {
    Backdrop,
  },
  data(): Data {
    return {
      username: "",
      password: "",
      busy: false,
      error: null,
    };
  },
  methods: {
    ...mapMutations(["setLoggedin"]),
    async login(): Promise<void> {
      this.busy = true;
      try {
        await api.login(this.username, this.password, "pam");
      } catch (e) {
        this.busy = false;
        if (e.status === 401) {
          this.error = "Invalid credentials";
        } else {
          console.error("LoginError", e);
          this.error = e;
        }
        return;
      }

      this.busy = false;
      this.setLoggedin();
      getBaseInfo();
      this.$router.push({ name: "jobs" });
    },
  },
});
