import moment from "moment";
import {
  Jid,
  Job,
  JobArgument,
  JobBaseResponse,
  JobDataStatus,
  JobResultMinion,
  JobStatus,
  Minion,
  Retcode,
} from "@/store/jobs/types";

const ignoreArgs = ["__kwarg__", "queue", "concurrent"];

export function convertJobBaseResponseToJob(
  anyJob: JobBaseResponse,
  jid: Jid,
  extra?: {
    Result: Record<Minion, JobResultMinion>;
    Minions: Minion[];
  }
): Job {
  let Result: Record<Minion, JobResultMinion> = {};
  let Minions: Minion[] = [];
  if (extra) {
    ({ Result, Minions } = extra);
  }
  const resultsCodes: Record<Minion, Retcode> = {};
  if (Result) {
    Object.keys(Result).forEach((minion: Minion) => {
      const jobResultMinion: JobResultMinion = Result[minion];
      resultsCodes[minion] = jobResultMinion.retcode;
    });
  }

  return {
    _stamp: moment(anyJob.StartTime, "YYYY, MMM D HH:mm:ss.SSSSSS").format(),
    jid: jid,
    arg: anyJob.Arguments || [],
    fun: anyJob.Function,
    tgt: anyJob.Target,
    tgtType: anyJob["Target-type"],
    user: anyJob.User,
    dataStatus: JobDataStatus.BASIC,
    minions: Minions || [],
    missing: [],
    resultsCodes,
    results: Result || {},
  };
}

export function calculateJobStatus(job: Job): JobStatus {
  if (job.dataStatus !== JobDataStatus.FULL) {
    return JobStatus.UNKNOWN;
  }

  if (Object.keys(job.results).length < job.minions.length) {
    return JobStatus.RUNNING;
  }

  const allSuccess: boolean = Object.values(job.results).every(
    (jobResultMinion: JobResultMinion) =>
      jobResultMinion.retcode === Retcode.SUCCESS
  );

  return allSuccess ? JobStatus.SUCCESS : JobStatus.FAILED;
}

export function formatArgs(args: JobArgument[]): string {
  return args
    .map((arg) => {
      let argList: string[] = [];
      if (typeof arg === "object") {
        Object.keys(arg).forEach((key: string) => {
          if (ignoreArgs.indexOf(key) === -1) {
            argList.push(`${key}=${arg[key]}`);
          }
        });
      } else {
        argList = [arg];
      }
      return argList.join(", ");
    })
    .join(" ");
}
