import { ActionContext, Module } from "vuex";
import { RootState } from "../types";
import { WheelState } from "@/store/wheel/types";
import { Minion } from "@/store/jobs/types";

type WheelActionContext = ActionContext<WheelState, RootState>;

export const wheelState: WheelState = {
  minionsRejected: [],
  minionsDenied: [],
  minionsPre: [],
  minions: [],
};

export const wheelModule: Module<WheelState, RootState> = {
  namespaced: true,
  state: wheelState,
  getters: {},
  actions: {
    setMinions({ commit }: WheelActionContext, minions: Minion[]): void {
      commit("setMinions", minions);
    },
    setMinionsRejected(
      { commit }: WheelActionContext,
      minions: Minion[]
    ): void {
      commit("setMinionsRejected", minions);
    },
    setMinionsDenied({ commit }: WheelActionContext, minions: Minion[]): void {
      commit("setMinionsDenied", minions);
    },
    setMinionsPre({ commit }: WheelActionContext, minions: Minion[]): void {
      commit("setMinionsPre", minions);
    },
  },
  mutations: {
    setMinions(state: WheelState, minions: Minion[]): void {
      state.minions = minions;
    },
    setMinionsRejected(state: WheelState, minions: Minion[]): void {
      state.minionsRejected = minions;
    },
    setMinionsDenied(state: WheelState, minions: Minion[]): void {
      state.minionsDenied = minions;
    },
    setMinionsPre(state: WheelState, minions: Minion[]): void {
      state.minionsPre = minions;
    },
  },
};
