














































































import Vue from "vue";
import moment, { Moment } from "moment";
import { mapActions, mapGetters } from "vuex";
import { formatArgs } from "@/store/jobs/utils";
import {
  Job,
  JobDataStatus,
  JobResult,
  JobResultMinion,
  Minion,
  Out,
  Retcode,
} from "@/store/jobs/types";
import JobResultMinionComponent from "@/components/JobResultMinion.vue";

interface Data {
  Retcode: typeof Retcode;
  timeRunning: string;
  interval: undefined | number;
  secondsCounter: number;
  viewMode: string;
  viewModes: string[];
}

export default Vue.extend({
  name: "JobDetail",
  components: {
    JobResultMinion: JobResultMinionComponent,
  },
  props: {
    jid: {
      type: String,
      required: true,
    },
  },
  data(): Data {
    return {
      Retcode,
      timeRunning: "",
      interval: undefined,
      secondsCounter: 0,
      viewMode: "all",
      viewModes: ["failed", "all", "changed", "unchanged"],
    };
  },
  async created(): Promise<void> {
    if (this.job) {
      if (this.job.dataStatus === JobDataStatus.BASIC) {
        await this.updateJobDetails(this.jid);
      }
      if (!this.isReady) {
        this.interval = setInterval(() => {
          this.secondsCounter += 1;
        }, 1000);
      }
    }
  },
  beforeDestroy(): void {
    clearInterval(this.interval);
  },
  watch: {
    async job(job): Promise<void> {
      if (job && job.dataStatus === JobDataStatus.BASIC) {
        await this.updateJobDetails(this.jid);
      }
    },
    isReady(value): void {
      if (value) {
        clearInterval(this.interval);
      }
    },
    secondsCounter(): void {
      if (this.job) {
        const duration = moment.duration(
          moment().diff(this.timeStamp as Moment)
        );
        let format = "s";
        if (duration.hours()) {
          format = "H:mm:ss";
        } else if (duration.minutes()) {
          format = "m:ss";
        }
        const timeRunning = moment(duration.asMilliseconds()).format(format);
        this.timeRunning = `${timeRunning} seconds`;
      }
    },
  },
  computed: {
    ...mapGetters("jobs", ["getJob"]),
    job(): Job | null {
      const job: Job = this.getJob(this.jid);
      if (job) {
        return Object.assign({}, job);
      }
      return null;
    },
    minions(): Minion[] {
      return this.job ? this.job.minions : [];
    },
    results(): JobResult {
      return this.job ? this.job.results : {};
    },
    hasResults(): boolean {
      return !!Object.keys(this.results).length;
    },
    hasFailed(): boolean {
      return (
        this.hasResults &&
        Object.values(this.results).some(
          (result: JobResultMinion) => result.retcode !== Retcode.SUCCESS
        )
      );
    },
    isReady(): boolean {
      return (
        !!this.job &&
        !!this.minions.length &&
        this.minions.length === Object.keys(this.job.resultsCodes).length
      );
    },
    formattedArgs(): string {
      return this.job ? formatArgs(this.job.arg) : "";
    },
    timeStamp(): Moment | null {
      return this.job ? moment.utc(this.job._stamp).local() : null;
    },
    ishHighstate(): boolean {
      return (
        this.hasResults && Object.values(this.results)[0].out === Out.HIGHSTATE
      );
    },
  },
  methods: {
    moment,
    ...mapActions("jobs", ["updateJobDetails"]),
  },
});
