
























import Vue from "vue";
import { mapGetters } from "vuex";
import { Job } from "@/store/jobs/types";
import JobTableRow from "@/components/JobTableRow.vue";

export default Vue.extend({
  name: "Jobs",
  components: {
    JobTableRow,
  },
  computed: {
    ...mapGetters("jobs", ["jobList"]),
    filteredJobList(): Job[] {
      return this.jobList.slice(0, 30);
    },
  },
});
