











import Vue from "vue";
import $ from "jquery";

export default Vue.extend({
  name: "JobProgress",
  components: {},
  props: {
    total: {
      type: Number,
    },
    successCount: {
      type: Number,
    },
    failedCount: {
      type: Number,
    },
  },
  mounted() {
    $(this.$el).progress({
      showActivity: false,
      autoSuccess: false,
      label: "ratio",
      text: {
        ratio: "{value}",
      },
      total: this.total,
      value: `${this.successCount}, ${this.failedCount}` as never,
    });
  },
  beforeDestroy() {
    $(this.$el).progress("destroy");
  },
  watch: {
    total(total: number): void {
      $(this.$refs.progress).progress("set total", total);
    },
    successCount(): void {
      $(this.$refs.progress).progress(
        "set progress" as never,
        `${this.successCount}, ${this.failedCount}`
      );
    },
    failedCount(): void {
      $(this.$refs.progress).progress(
        "set progress" as never,
        `${this.successCount}, ${this.failedCount}`
      );
    },
  },
});
