import Vue from "vue";
import { ActionContext, Module } from "vuex";
import { RootState } from "../types";
import {
  Jid,
  Job,
  JobDataStatus,
  JobResultMinion,
  Jobs,
  JobsState,
  Minion,
  Retcode,
  RunnerJobsListJobResponse,
} from "@/store/jobs/types";
import { convertJobBaseResponseToJob } from "@/store/jobs/utils";
import { api } from "@/api";

type JobActionContext = ActionContext<JobsState, RootState>;

interface JobGetters {
  jobListRunning: Job[];
  jobList: Job[];
  getJob(jid: Jid): Job | undefined;
}

export const jobsState: JobsState = {
  jobs: {},
};

export const jobsModule: Module<JobsState, RootState> = {
  namespaced: true,
  state: jobsState,
  getters: {
    jobListRunning(state: JobsState, getters: JobGetters): Job[] {
      return getters.jobList.filter((job: Job) => {
        const minionCount = job.minions.length;
        const resultCount = Object.keys(job.resultsCodes).length;
        return resultCount < minionCount;
      });
    },
    jobList(state: JobsState): Job[] {
      return Object.keys(state.jobs)
        .map((jid: Jid) => {
          const obj = state.jobs[jid];
          obj.jid = jid;
          return obj;
        })
        .sort((a: Job, b: Job) => {
          return Number(b.jid) - Number(a.jid);
        });
    },
    getJob: (state: JobsState) => (jid: Jid): Job | undefined =>
      state.jobs[jid],
  },
  actions: {
    setMinions(
      { commit }: JobActionContext,
      { jid, minions }: { jid: Jid; minions: Minion[] }
    ): void {
      commit("setMinions", { jid, minions });
    },
    addNewJob({ commit }: JobActionContext, job: Job): void {
      commit("addNewJob", job);
    },
    addJobResult(
      { commit }: JobActionContext,
      {
        resultMinion,
        minion,
        jid,
      }: { jid: Jid; resultMinion: JobResultMinion; minion: Minion }
    ): void {
      commit("addJobResult", { jid, resultMinion, minion });
      commit("addJobResultCodes", {
        jid,
        retcode: resultMinion.retcode,
        minion,
      });
      commit("addMinion", { jid, minion });
    },
    updateJobs({ commit }: JobActionContext, jobs: Jobs): void {
      commit("updateJobs", jobs);
    },
    async updateJobDetails(
      { commit, dispatch }: JobActionContext,
      jid: Jid
    ): Promise<boolean> {
      commit("setJobDataStatus", {
        jid,
        dataStatus: JobDataStatus.LOADING_DETAILS,
      });
      let responseJob: RunnerJobsListJobResponse | void;
      try {
        responseJob = await api.getRunnerJobsListJob(jid);
      } catch (e) {
        commit("setJobDataStatus", { jid, dataStatus: JobDataStatus.BASIC });
        console.warn(e);
      }
      if (responseJob) {
        const jobInfo: Job = convertJobBaseResponseToJob(responseJob, jid, {
          Minions: responseJob.Minions,
          Result: responseJob.Result,
        });
        if (jobInfo.minions.length) {
          dispatch("setMinions", { jid: jid, minions: jobInfo.minions });
        }
        if (jobInfo.results) {
          Object.keys(jobInfo.results).forEach((minion: Minion) => {
            const resultMinion: JobResultMinion = jobInfo.results[minion];
            dispatch("addJobResult", { jid, resultMinion, minion });
          });
        }
        commit("setJobDataStatus", { jid, dataStatus: JobDataStatus.FULL });
        return true;
      } else {
        commit("setJobDataStatus", { jid, dataStatus: JobDataStatus.BASIC });
      }
      return false;
    },
  },
  mutations: {
    setMinions(
      state: JobsState,
      { jid, minions }: { jid: Jid; minions: Minion[] }
    ): void {
      Vue.set(state.jobs[jid], "minions", minions);
    },
    addMinion(
      state: JobsState,
      { jid, minion }: { jid: Jid; minion: Minion }
    ): void {
      if (state.jobs[jid].minions.indexOf(minion) === -1) {
        state.jobs[jid].minions.push(minion);
      }
    },
    addNewJob(state: JobsState, job: Job): void {
      Vue.set(state.jobs, job.jid, job);
    },
    setJobDataStatus(
      state: JobsState,
      { jid, dataStatus }: { jid: Jid; dataStatus: JobDataStatus }
    ): void {
      state.jobs[jid].dataStatus = dataStatus;
    },
    addJobResult(
      state: JobsState,
      {
        jid,
        resultMinion,
        minion,
      }: { jid: Jid; resultMinion: JobResultMinion; minion: Minion }
    ): boolean {
      if (!state.jobs[jid]) {
        console.error(
          `Trying to add job result with jid: ${jid}, but job does not exists`
        );
        return false;
      }
      if (!state.jobs[jid].results) {
        Vue.set(state.jobs[jid], "results", {});
      }
      Vue.set(state.jobs[jid].results, minion, resultMinion);
      return true;
    },
    addJobResultCodes(
      state: JobsState,
      { jid, retcode, minion }: { jid: Jid; retcode: Retcode; minion: Minion }
    ): void {
      Vue.set(state.jobs[jid].resultsCodes, minion, retcode);
    },
    updateJobs(state: JobsState, jobs: Jobs): void {
      Object.entries(jobs).forEach((entry) => {
        const [jid, job] = entry;
        Vue.set(state.jobs, jid, job);
      });
    },
  },
};
