// External
import Vue from "vue";
import Vuex, { StoreOptions } from "vuex";
// Types
import { Perms, RootState } from "./types";
import { wheelModule } from "@/store/wheel";
import { jobsModule } from "@/store/jobs";
// Store

Vue.use(Vuex);

const storeOptions: StoreOptions<RootState> = {
  strict: process.env.NODE_ENV !== "production",
  state: {
    version: process.env.VERSION,
    loggedin: false,
    user: window.sessionStorage.getItem("user") || "",
    perms: JSON.parse(window.sessionStorage.getItem("perms") || "{}") as Perms,
  },
  getters: {
    hasPerm: (state: RootState) => ({
      module,
      perm,
    }: {
      module: string;
      perm: string;
    }) => {
      if (module in state.perms) {
        return state.perms[module].indexOf(perm) !== -1;
      }
      return false;
    },
  },
  actions: {
    setUser({ commit }, user: string) {
      commit("setUser", user);
      window.sessionStorage.setItem("user", user);
    },
    setPerms({ commit }, perms: Perms) {
      commit("setPerms", perms);
      window.sessionStorage.setItem("perms", JSON.stringify(perms));
    },
  },
  mutations: {
    setLoggedin(state) {
      state.loggedin = true;
    },
    setLoggedout(state) {
      state.loggedin = false;
      window.sessionStorage.removeItem("user");
      window.sessionStorage.removeItem("perms");
    },
    setUser(state, user: string) {
      state.user = user;
    },
    setPerms(state, perms: Perms) {
      state.perms = perms;
    },
  },
  modules: {
    wheel: wheelModule,
    jobs: jobsModule,
  },
};

const store = new Vuex.Store<RootState>(storeOptions);

export default store;
