





























































































import Vue from "vue";
import Highlight from "@/components/Highlight.vue";
import { AnyObject } from "@/store/types";

export enum DataDisplay {
  JSON = "JSON",
  DATA_TABLE = "DATA_TABLE",
  DEFINITION_TABLE = "DEFINITION_TABLE",
}

interface Data {
  DataDisplay: typeof DataDisplay;
  activeDataDisplay: DataDisplay;
}

export default Vue.extend({
  name: "ValueDisplay",
  components: {
    Highlight,
  },
  props: {
    title: {
      type: String,
      default: "",
    },
    value: {
      type: [String, Number, Object, Array, Boolean],
      required: true,
    },
  },
  data(): Data {
    return {
      DataDisplay,
      activeDataDisplay: DataDisplay.JSON,
    };
  },
  created(): void {
    if (this.allowDataTable) {
      this.activeDataDisplay = DataDisplay.DATA_TABLE;
    } else if (this.allSimpleValues) {
      this.activeDataDisplay = DataDisplay.DEFINITION_TABLE;
    }
  },
  computed: {
    isSimpleValue(): boolean {
      return typeof this.value !== "object";
    },
    isArray(): boolean {
      return Array.isArray(this.value);
    },
    isObject(): boolean {
      return typeof this.value === "object" && !this.isArray;
    },
    isEmpty(): boolean {
      if (typeof this.value === "object") {
        return !Object.keys(this.value).length;
      }
      return !this.value;
    },
    displayOptions(): string[] {
      if (!this.isObject) {
        return [];
      }
      const displayOptions = [DataDisplay.JSON, DataDisplay.DEFINITION_TABLE];
      if (this.isEmpty) {
        return [];
      }
      if (this.allowDataTable) {
        displayOptions.push(DataDisplay.DATA_TABLE);
      }
      return displayOptions;
    },
    allSimpleValues(): boolean {
      if (!this.isObject) {
        return false;
      }
      return Object.values(this.value).every(
        (value: unknown) => typeof value !== "object"
      );
    },
    allowDataTable(): boolean {
      if (!this.isObject) {
        return false;
      }
      let columns = "";
      return Object.values(this.value).every((change: unknown) => {
        if (typeof change !== "object") {
          return false;
        }
        if (!columns.length) {
          columns = Object.keys(change as AnyObject).join("");
          return true;
        }
        return Object.keys(change as AnyObject).join("") === columns;
      });
    },
    dataTableHeader(): string[] {
      if (this.allowDataTable) {
        const value = Object.values(this.value as AnyObject)[0] as AnyObject;
        return Object.keys(value);
      }
      return [];
    },
  },
});
