



























































import Vue from "vue";
import ValueDisplay from "@/components/ValueDisplay.vue";

interface Data {
  expanded: boolean;
}

export default Vue.extend({
  name: "HighstateResult",
  components: {
    ValueDisplay,
  },
  props: {
    resultItem: {
      type: [Object, String, Boolean], // JobResultObject | JobResultHighState,
      required: true,
    },
  },
  data(): Data {
    return {
      expanded: false,
    };
  },
  computed: {
    title(): string {
      return this.resultItem.__id__ || this.resultItem.__sls__;
    },
    canExpand(): boolean {
      return !!(
        (this.resultItem.changes &&
          Object.keys(this.resultItem.changes).length) ||
        (this.resultItem.pchanges &&
          Object.keys(this.resultItem.pchanges).length)
      );
    },
    isString(): boolean {
      return typeof this.resultItem === "string";
    },
    totalDuration(): number {
      return Math.round(this.resultItem.duration);
    },
    durationColorClass(): string {
      if (this.resultItem.duration > 1000) {
        return "red";
      }
      if (this.resultItem.duration > 500) {
        return "orange";
      }
      if (this.resultItem.duration > 100) {
        return "yellow";
      }
      return "";
    },
  },
});
