

















































import Vue, { PropType } from "vue";
import { mapActions } from "vuex";
import moment, { Moment } from "moment";
import { Job, JobDataStatus, JobStatus, Retcode } from "@/store/jobs/types";
import { calculateJobStatus, formatArgs } from "@/store/jobs/utils";
import JobProgress from "@/components/JobProgress.vue";

interface Data {
  JobStatus: typeof JobStatus;
  JobDataStatus: typeof JobDataStatus;
}

export default Vue.extend({
  name: "JobTableRow",
  components: {
    JobProgress,
  },
  props: {
    job: {
      type: Object as PropType<Job>,
      required: true,
    },
  },
  data(): Data {
    return {
      JobStatus,
      JobDataStatus,
    };
  },
  computed: {
    jobStatus(): JobStatus {
      return calculateJobStatus(this.job);
    },
    minionCount(): number {
      return this.job.minions.length;
    },
    successCount(): number {
      return Object.values(this.job.resultsCodes).filter(
        (retcode: Retcode) => retcode === Retcode.SUCCESS
      ).length;
    },
    failedCount(): number {
      return Object.values(this.job.resultsCodes).filter(
        (retcode: Retcode) => retcode !== Retcode.SUCCESS
      ).length;
    },
    formattedArgs(): string {
      return formatArgs(this.job.arg);
    },
    timeStamp(): Moment {
      return moment.utc(this.job._stamp).local();
    },
  },
  methods: {
    ...mapActions("jobs", ["updateJobDetails"]),
    updateStatus(): void {
      this.updateJobDetails(this.job.jid);
    },
  },
});
