







































import Vue, { PropType } from "vue";
import HighstateResultComponent from "@/components/HighstateResult.vue";
import { HighstateResult } from "@/store/jobs/types";

interface Data {
  expanded: boolean;
}

export default Vue.extend({
  name: "HighstateResultGroup",
  components: {
    HighstateResult: HighstateResultComponent,
  },
  props: {
    sls: {
      type: String,
      required: true,
    },
    results: {
      type: Array as PropType<HighstateResult[]>,
      required: true,
    },
    viewMode: {
      type: String,
      default: "all",
    },
  },
  data(): Data {
    return {
      expanded: false,
    };
  },
  computed: {
    resultsFiltered(): HighstateResult[] {
      return this.results.filter(this.matchViewModeResult);
    },
    matchViewMode(): boolean {
      return (
        this.viewMode === "all" ||
        (this.viewMode === "failed" && !!this.failedLines) ||
        (this.viewMode === "changed" && !!this.changedLines) ||
        (this.viewMode === "unchanged" && !!this.unchangedLines)
      );
    },
    totalLines(): number {
      return this.results.length;
    },
    failedLines(): number {
      return this.results.filter(
        (highstateResult) => highstateResult.result === false
      ).length;
    },
    changedLines(): number {
      return this.results.filter(
        (highstateResult) =>
          highstateResult.changes && Object.keys(highstateResult.changes).length
      ).length;
    },
    unchangedLines(): number {
      return this.results.filter(
        (highstateResult) => highstateResult.result === null
      ).length;
    },
    successLines(): number {
      return this.results.filter(
        (highstateResult) => highstateResult.result === true
      ).length;
    },
    success(): boolean {
      return this.successLines === this.totalLines;
    },
    successPercentage(): number {
      return (this.successLines / this.totalLines) * 100;
    },
    totalDuration(): number {
      return Math.round(
        this.results.reduce((previousValue, highstateResult) => {
          return previousValue + highstateResult.duration;
        }, 0)
      );
    },
    durationColorClass(): string {
      if (this.totalDuration > 1000) {
        return "red";
      }
      if (this.totalDuration > 500) {
        return "orange";
      }
      if (this.totalDuration > 100) {
        return "yellow";
      }
      return "";
    },
  },
  methods: {
    matchViewModeResult(highstateResult: HighstateResult) {
      return (
        this.viewMode === "all" ||
        (this.viewMode === "failed" && highstateResult.result === false) ||
        (this.viewMode === "changed" &&
          highstateResult.changes &&
          Object.keys(highstateResult.changes).length) ||
        (this.viewMode === "unchanged" && highstateResult.result === null)
      );
    },
  },
});
