import {
  Jid,
  JobResultMinion,
  JobReturn,
  Minion,
  Out,
  Retcode,
} from "@/store/jobs/types";
import store from "@/store";

export interface SaltJobRetResponse {
  out?: Out;
  _stamp: string;
  cmd: string;
  fun: string;
  fun_args: string[];
  id: Minion;
  jid: Jid;
  retcode: Retcode;
  return: JobReturn;
  success: boolean;
}

export const saltJobRetListener = async (
  tag: string,
  data: SaltJobRetResponse
): Promise<void> => {
  if (!data.fun.startsWith("saltutil.")) {
    const minion: Minion = tag.split("/")[4];
    const resultMinion: JobResultMinion = {
      out: data.out,
      retcode: data.retcode,
      return: data.return,
      success: data.success,
    };
    await store.dispatch("jobs/addJobResult", {
      jid: data.jid,
      resultMinion: resultMinion,
      minion: minion,
    });
  }
};
