




















































import $ from "jquery";
import Vue from "vue";
import { api } from "@/api";
import { ExecuteResult } from "@/store/local/types";

export default Vue.extend({
  name: "JobRunner",
  data() {
    return {
      runState: true,
      target: "",
      state: "",
      test: false,
    };
  },
  mounted() {
    $(this.$refs.stateToggle).checkbox();
    $(this.$refs.toggleTest).checkbox();
  },
  methods: {
    async execute(): Promise<void> {
      let result: void | ExecuteResult;
      try {
        if (this.runState) {
          result = await api.runState(this.target, this.state, "", this.test);
        } else {
          result = await api.execute(this.target, this.state, "");
        }
      } catch (error) {
        console.log("JobRunner", error);
        alert(error.message);
        return;
      }

      if (result && Object.keys(result).length) {
        await this.$router.push({ name: "job", params: { jid: result.jid } });
      }
    },
  },
});
