

































































import Vue, { PropType } from "vue";
import {
  HighstateResult,
  JobResultHighState,
  JobResultMinion,
  Out,
  Retcode,
} from "@/store/jobs/types";
import HighstateResultGroup from "@/components/HighstateResultGroup.vue";
import ValueDisplay from "@/components/ValueDisplay.vue";

interface Data {
  Out: typeof Out;
  Retcode: typeof Retcode;
  expanded: boolean;
}

interface GroupResult {
  sls: string;
  results: HighstateResult[];
}

export default Vue.extend({
  name: "JobResultMinion",
  components: {
    ValueDisplay,
    HighstateResultGroup,
  },
  props: {
    jobResultMinion: {
      type: Object as PropType<JobResultMinion>,
      required: false,
    },
    minion: {
      type: String,
      required: true,
    },
    viewMode: {
      type: String,
      default: "all",
    },
  },
  data(): Data {
    return {
      Out,
      Retcode,
      expanded: false,
    };
  },
  mounted(): void {
    if (this.isLoaded && this.jobResultMinion.retcode === Retcode.FAILED) {
      this.expanded = true;
    }
  },
  watch: {
    viewMode(value): void {
      if (value === "failed" && !this.expanded) {
        this.expanded = true;
      }
    },
  },
  computed: {
    isLoaded(): boolean {
      return !!this.jobResultMinion;
    },
    isHighstate(): boolean {
      return (
        this.jobResultMinion.out === Out.HIGHSTATE &&
        typeof this.jobResultMinion.return === "object"
      );
    },
    totalLines(): number {
      if (this.isHighstate) {
        return Object.keys(this.jobResultMinion.return).length;
      }
      return 1;
    },
    successLines(): number {
      if (this.isHighstate) {
        return Object.values(this.jobResultMinion.return).filter(
          (highstateResult) => {
            return highstateResult.result;
          }
        ).length;
      }
      return this.jobResultMinion.success ? 1 : 0;
    },
    failedLines(): number {
      return this.totalLines - this.successLines;
    },
    successPercentage(): number {
      return (this.successLines / this.totalLines) * 100;
    },
    sortedResults(): HighstateResult[] {
      const jobs = this.jobResultMinion.return as JobResultHighState;
      return Object.values(jobs).sort(
        (a: HighstateResult, b: HighstateResult) =>
          a.__run_num__ - b.__run_num__
      );
    },
    groupedResults(): GroupResult[] {
      const groupsResults: GroupResult[] = [];
      this.sortedResults.forEach((result: HighstateResult) => {
        if (
          !groupsResults.length ||
          groupsResults[groupsResults.length - 1].sls !== result.__sls__
        ) {
          groupsResults.push({
            sls: result.__sls__,
            results: [],
          });
        }
        groupsResults[groupsResults.length - 1].results.push(result);
      });
      return groupsResults;
    },
  },
});
