import { api } from "@/api";
import {
  Jid,
  Jobs,
  RunnerJobsActiveResponse,
  RunnerJobsListJobsResponse,
} from "@/store/jobs/types";
import { convertJobBaseResponseToJob } from "@/store/jobs/utils";
import store from "@/store/index";
import { startConsumingEvents } from "@/store/events/consume-events";
import { WheelKeyListAllResponse } from "@/store/wheel/types";

export const getBaseInfo = (): void => {
  // Get all available minions
  api
    .getWheelKeyListAll()
    .then(async (result: WheelKeyListAllResponse | void) => {
      if (result) {
        const data = result.data.return;
        await store.dispatch("wheel/setMinions", data.minions);
        await store.dispatch("wheel/setMinionsRejected", data.minions_rejected);
        await store.dispatch("wheel/setMinionsDenied", data.minions_denied);
        await store.dispatch("wheel/setMinionsPre", data.minions_pre);
      }
    });

  // Get running jobs
  function refreshActiveJobs() {
    api
      .getRunnerJobsActive()
      .then(async (jobs: RunnerJobsActiveResponse | void) => {
        if (jobs) {
          const filteredJobs: Jobs = Object.keys(jobs).reduce(
            (result: Jobs, jid: Jid) => {
              const job = jobs[jid];
              if (!job.Function.startsWith("saltutil.")) {
                result[jid] = convertJobBaseResponseToJob(job, jid);
                store.dispatch("jobs/updateJobDetails", jid);
              }
              return result;
            },
            {}
          );

          await store.dispatch("jobs/updateJobs", filteredJobs);
        }
      });
  }

  refreshActiveJobs();

  // Get today's jobs
  // TODO: Duplicate code block
  api
    .getRunnerJobsListJobs()
    .then(async (jobs: RunnerJobsListJobsResponse | void) => {
      if (jobs) {
        const filteredJobs: Jobs = Object.keys(jobs).reduce(
          (result: Jobs, jid: Jid) => {
            const job = jobs[jid];
            if (!job.Function.startsWith("saltutil.")) {
              result[jid] = convertJobBaseResponseToJob(job, jid);
            }
            return result;
          },
          {}
        );

        await store.dispatch("jobs/updateJobs", filteredJobs);
      }
    });

  // const noop = () => {};
  // api.getWheelKeyFinger().then(noop);
  // api.getWheelConfigValues().then(noop);
  // api.getLocalGrainsItems('app01').then(noop);
  // api.getLocalPillarItems('app01').then(noop);
  // api.getLocalPillarObfuscate('app01').then(noop);
  // api.getLocalScheduleList('app01').then(noop);

  startConsumingEvents();
};
